('spanish:5-1-food-customs-and-daily-life:mcq:2d30d19b', 'spanish', 'spanish:5-1-food-customs-and-daily-life', '5.1 Food Customs and Daily Life', 'mcq', 'mcq', 1, '{"question": "‘De pequeño, me acostaba temprano’ describes…", "options": ["a habit from the past, using the imperfect tense", "something that is happening right at this very moment", "a plan for tomorrow, using the near future", "an instruction telling someone what to do"]}'::jsonb, '{"answer": 0, "explain": "‘de pequeño’ + the imperfect (me acostaba) describes a repeated childhood habit."}'::jsonb),
